import { describe, it, expect } from 'vitest';
import { controlComp, runComp, unitOf, withPatchedOverride } from '../lib/harness';

// ============================================================================
// marciana-marine-study — BLIND post-op kit spec (S5). Written from kit prose
// ALONE; blind to the driver's override/tests/reasoning.
//
// Kit (AR / Iron / Attacker / Burst III; ammo 60, reloadFrames 81):
//  S1a  FB-enter AFTER this unit uses her OWN burst, on highest-Max-HP enemy:
//         3789.25% ATK additional-damage rider (+ enemy ATK\u25bc10.56%/10s = defensive\u2192inert).
//         Trigger = fullBurstEnter + ownBurstGate:'cast' (NOT plain burstCast, NOT plain FB-enter).
//  S1b  on-enemy-neutralized while Flagged: another 3789.25% rider.
//         \u2192 GAP: solo raid has one immortal boss, no neutralize events.
//  S1c  every 20 normal hits vs a High-Risk target: 152.68% rider.
//         \u2192 High-Risk is applied ONLY to Electric enemies (burst), so INERT on a Fire boss.
//  S2a  battle start: Whistle ATK\u25b232.73%/stack, +4 stacks (cap 5).
//  S2b  \u22643 Raptures / 5s: +1 Whistle stack \u2192 caps at 5 (boss = 1 Rapture, always true).
//         Steady state \u2248 5 stacks = 163.65% ATK (first ~5s at 4 stacks; \u26a1 minor ramp).
//  S2c  \u22656 Raptures / 1s: Penguin Dispatch 214.36% AoE, \u22121 Whistle.
//         \u2192 GAP: solo raid never has 6+ Raptures; also means Whistle never drains \u2192 stays 5.
//  S2d  Rapture appears/neutralized while \u22645 present: Elem-Adv Attack Damage\u25b220.41%.
//         \u2192 INERT: Iron vs Fire boss = no elemental advantage.
//  burst self: Elem-Adv Attack Damage\u25b230.97%/10s [INERT, no advantage] + Attack Damage\u25b227.45%/10s.
//  burst all-Electric enemies: High-Risk DEF\u25bc10.56%/20s [INERT, boss is Fire].
//
// Fixture: controlComp('marciana-marine-study', true) \u2014 liter B1 / crown B2 /
//   marciana B3 (focus, slot 3) / helm B3, boss Fire. Deterministic (no seed).
//   The two-B3 shape (marciana + helm) is what could exercise the S1a ownBurstGate.
//
// Discriminators are built COUNTERFACTUALLY via withPatchedOverride so they do not
// depend on internal event field names: remove/rekey the block, re-run, compare
// marciana's total (removeRider < misKeyedAsBurstCast < faithful) \u2014 this pins BOTH
// that the rider fires AND that it fires INSIDE Full Burst (takes the +50% major).
// ============================================================================

const SLUG = 'marciana-marine-study';
const near = (a, b, tol = 0.5) => Math.abs(a - b) < tol;

function mTotal(res) { return unitOf(res, SLUG).total; }
function slugTotal(res, slug) { return unitOf(res, slug).total; }

function hasFlat(b, pct) {
  return (b.effects || []).some(e => e.kind === 'flatDamage' && near(e.atkPct, pct));
}

function runWithEvents(opts) {
  const events = [];
  opts.cfg = { ...(opts.cfg || {}), onEvent: e => events.push(e) };
  const res = runComp(opts);
  return { res, events };
}

// ---- hoisted runs (each runComp is a full 180s sim) ------------------------
const { res: BASE, events: EV } = runWithEvents(controlComp(SLUG, true));

const NO_RIDER = runComp(withPatchedOverride(SLUG, ov => {
  ov.blocks = ov.blocks.filter(b => !hasFlat(b, 3789.25));
}) && controlCompPatched(SLUG));

// withPatchedOverride returns an in-memory override clone the harness reads when
// runComp is called for this slug; controlComp then builds the comp using it.
function controlCompPatched(slug) { return controlComp(slug, true); }

const NO_RIDER_RES = runComp((withPatchedOverride(SLUG, ov => {
  ov.blocks = ov.blocks.filter(b => !hasFlat(b, 3789.25));
}), controlComp(SLUG, true)));

const MISKEY_RES = runComp((withPatchedOverride(SLUG, ov => {
  for (const b of ov.blocks)
    if (hasFlat(b, 3789.25) && b.trigger && b.trigger.kind === 'fullBurstEnter')
      b.trigger = { kind: 'burstCast' };
}), controlComp(SLUG, true)));

const NO_WHISTLE_RES = runComp((withPatchedOverride(SLUG, ov => {
  for (const b of ov.blocks)
    b.effects = (b.effects || []).filter(e => !(e.kind === 'buff' && e.stat === 'atkPct'));
}), controlComp(SLUG, true)));

const NO_ELEMADV_RES = runComp((withPatchedOverride(SLUG, ov => {
  for (const b of ov.blocks)
    b.effects = (b.effects || []).filter(e => !(e.kind === 'buff' && e.stat === 'elemAdvantageDamagePct'));
}), controlComp(SLUG, true)));

const NO_HIGHRISK_RIDER_RES = runComp((withPatchedOverride(SLUG, ov => {
  ov.blocks = ov.blocks.filter(b => !hasFlat(b, 152.68));
}), controlComp(SLUG, true)));

const UNGATED_RES = runComp((withPatchedOverride(SLUG, ov => {
  for (const b of ov.blocks) if (b.ownBurstGate) delete b.ownBurstGate;
}), controlComp(SLUG, true)));

const NO_BURST_ATKDMG_RES = runComp((withPatchedOverride(SLUG, ov => {
  for (const b of ov.blocks)
    b.effects = (b.effects || []).filter(e => !(e.kind === 'buff' && e.stat === 'attackDamagePct' && near(e.value, 27.45)));
}), controlComp(SLUG, true)));

describe('marciana-marine-study — kit faithfulness', () => {

  it('fixture non-vacuity: marciana bursts and the team reaches Full Burst', () => {
    expect(EV.filter(e => e.kind === 'fullBurstStart').length).toBeGreaterThan(0);
    expect(EV.filter(e => e.kind === 'burstCast').length).toBeGreaterThan(0);
    expect(mTotal(BASE)).toBeGreaterThan(0);
  });

  // S1a — the 3789.25% FB-enter-after-own-burst rider ------------------------
  it('S1a: the 3789.25% rider FIRES and adds substantial damage', () => {
    const contribution = mTotal(BASE) - mTotal(NO_RIDER_RES);
    expect(contribution).toBeGreaterThan(0);
    // a 3789% rider firing at least once is a large fraction of her total
    expect(contribution).toBeGreaterThan(mTotal(BASE) * 0.02);
  });

  it('S1a: the rider takes the +50% Full-Burst major (fullBurstEnter, NOT burstCast)', () => {
    // removeRider < misKeyedAsBurstCast < faithful:
    //  - misKey still deals the rider, so it beats removeRider
    //  - but keyed to burstCast it lands PRE-FB (no +50% FB major, no FB auras),
    //    so faithful fullBurstEnter must beat misKey.
    expect(mTotal(MISKEY_RES)).toBeGreaterThan(mTotal(NO_RIDER_RES));
    expect(mTotal(BASE)).toBeGreaterThan(mTotal(MISKEY_RES));
  });

  it('S1a: ownBurstGate never INCREASES fires vs an ungated rider (gate is faithful)', () => {
    // Removing ownBurstGate can only ADD fires (rider then triggers on any team FB,
    // incl. rotations helm completes). A faithful gated rider must be <= ungated.
    expect(mTotal(UNGATED_RES)).toBeGreaterThanOrEqual(mTotal(BASE) - 1e-6);
  });

  // S2a/S2b — Whistle self ATK stacks ----------------------------------------
  it('S2a/b: Whistle grants a large self ATK buff that scales all her damage', () => {
    const drop = mTotal(BASE) - mTotal(NO_WHISTLE_RES);
    expect(drop).toBeGreaterThan(0);
    // ~5 stacks x 32.73% is a big ATK lift; removing it should move her total clearly
    expect(drop).toBeGreaterThan(mTotal(BASE) * 0.05);
  });

  it('S2a/b: Whistle is a self ATK buff (a buffApply with stat atkPct is emitted)', () => {
    const atkBuffs = EV.filter(e => e.kind === 'buffApply' && e.stat === 'atkPct' && e.value > 0);
    expect(atkBuffs.length).toBeGreaterThan(0);
    // per-stack authoring -> ~32.73; lumped authoring -> ~130.92/163.65. Accept either.
    const ok = atkBuffs.some(e => near(e.value, 32.73) || near(e.value, 130.92, 2) || near(e.value, 163.65, 2));
    expect(ok).toBe(true);
  });

  it('S2a/b: Whistle is SELF-scoped — teammates are byte-identical without it', () => {
    for (const ally of ['liter', 'crown', 'helm']) {
      expect(slugTotal(NO_WHISTLE_RES, ally)).toBeCloseTo(slugTotal(BASE, ally), 6);
    }
  });

  // burst — Attack Damage +27.45% self ---------------------------------------
  it('burst: Attack Damage +27.45% self-buff is applied and contributes', () => {
    const buffs = EV.filter(e => e.kind === 'buffApply' && e.stat === 'attackDamagePct' && near(e.value, 27.45));
    expect(buffs.length).toBeGreaterThan(0);
    expect(mTotal(BASE)).toBeGreaterThan(mTotal(NO_BURST_ATKDMG_RES));
  });

  // ---- INERTNESS on the Fire-boss fixture ----------------------------------
  it('INERT: Elemental-Advantage damage lines move NOTHING (Iron vs Fire = neutral)', () => {
    // S2d 20.41% + burst 30.97% elemAdvantageDamagePct: no advantage on a Fire boss.
    expect(mTotal(NO_ELEMADV_RES)).toBeCloseTo(mTotal(BASE), 6);
  });

  it('INERT: the 152.68% High-Risk rider (S1c) never fires on a non-Electric boss', () => {
    // High-Risk is applied only to Electric enemies (burst), so the gate never opens.
    expect(mTotal(NO_HIGHRISK_RIDER_RES)).toBeCloseTo(mTotal(BASE), 6);
  });

  // ---- GAP lines (untestable on this fixture / missing primitive) -----------
  it.skip('S1b: on-enemy-neutralized 3789.25% rider — no neutralize events in solo raid', () => {});
  it.skip('S1c ACTIVE case: 152.68% every-20-normals rider — needs an Electric boss to open High-Risk', () => {});
  it.skip('S2c: Penguin Dispatch 214.36% AoE — needs 6+ Raptures present, impossible in solo raid', () => {});
  it.skip('S2d/burst ACTIVE case: Elem-Adv Attack Damage — needs an advantaged boss the harness cannot build', () => {});
});
